--
-- Table structure for table `students`
--

DROP TABLE IF EXISTS `students`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `students` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `school_id` int unsigned NOT NULL,
  `class_id` int unsigned DEFAULT NULL,
  `nis` varchar(40) DEFAULT NULL,
  `nisn` varchar(40) DEFAULT NULL,
  `email` varchar(160) DEFAULT NULL,
  `phone` varchar(30) DEFAULT NULL,
  `name` varchar(120) NOT NULL,
  `nickname` varchar(80) DEFAULT NULL,
  `gender` enum('L','P') DEFAULT NULL,
  `birth_place` varchar(120) DEFAULT NULL,
  `birth_date` date DEFAULT NULL,
  `religion` varchar(60) DEFAULT NULL,
  `parent_name` varchar(120) DEFAULT NULL,
  `parent_wa` varchar(30) DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `blood_type` varchar(5) DEFAULT NULL,
  `allergies` varchar(255) DEFAULT NULL,
  `medical_notes` text,
  `emergency_contact_name` varchar(120) DEFAULT NULL,
  `emergency_contact_phone` varchar(30) DEFAULT NULL,
  `status` enum('aktif','lulus','keluar') NOT NULL DEFAULT 'aktif',
  `photo_url` varchar(500) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_students_school` (`school_id`),
